commandLine.original:
$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
$lines = Get-Content $f | Where-Object { $_.Length -ge 40 -and $_ -like "*BT09TC*" }
"Total lines mentioning BT09TC: $($lines.Count)"
# classify: source = chars13-19 ; dest field starts at 20
$src = $lines | Where-Object { $_.Substring(13,7) -eq "FBT09TC" }
$dst = $lines | Where-Object { $_.Substring(13,7) -ne "FBT09TC" }
"FROM BT09TC (saidas): $($src.Count)"
"TO/other BT09TC: $($dst.Count)"
"--- sample dest field (pos20-30) for TO records ---"
$dst | Select-Object -First 5 | ForEach-Object { "'"+$_.Substring(20,11)+"' part="+$_.Substring(3,10).Trim() }

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
$dst = Get-Content $f | Where-Object { $_.Length -ge 40 -and $_ -like "*BT09TC*" -and $_.Substring(13,7) -ne "FBT09TC" }
$dst | Select-Object -First 3 | ForEach-Object { $idx = $_.IndexOf("BT09TC"); "BT09TCidx=$idx | from=$($_.Substring(13,7)) | $_" }

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
$src = Get-Content $f | Where-Object { $_.Length -ge 40 -and $_.Substring(13,7) -eq "FBT09TC" }
"=== Records FROM BT09TC (consumo/saida): $($src.Count) ==="
$src | ForEach-Object { "part={0} | dest='{1}' | qtyfield='{2}'" -f $_.Substring(3,10).Trim(), $_.Substring(20,12), $_.Substring(40,12) }

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
$l = Get-Content $f -TotalCount 1
"date@78='"+$l.Substring(78,10)+"'"
# But NGR lines had date at pos80 area too. Find slash positions generally
$dates = Get-Content $f | ForEach-Object {
  if($_.Length -ge 88){ $s=$_.Substring(78,10); if($s -match '^\d{2}/\d{2}/\d{4}$'){ $s } }
}
"Total com data valida @78: $($dates.Count)"
$dates | Group-Object | Sort-Object { [datetime]::ParseExact($_.Name,'dd/MM/yyyy',$null) } | Format-Table Count,Name -AutoSize

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
Get-Content $f | Where-Object { $_ -like "*61610022782*" } | ForEach-Object {
  $idx = $_.IndexOf("61610022782")
  "idx=$idx | rec=$($_.Substring(0,3)) | part=$($_.Substring(3,10).Trim()) | from=$($_.Substring(13,7)) | dest=$($_.Substring(20,12).Trim()) | data=$($_.Substring(78,10))"
  "  FULL: $_"
}

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
Get-Content $f | Where-Object { $_ -like "*61610022782*" } | ForEach-Object {
  $after = $_.Substring(88,8)
  "rec=$($_.Substring(0,3)) data=$($_.Substring(78,10)) campo_apos_data='$after'"
}

$f = "c:\Users\junioeg\robotics\robotics1\TRANVR2.TXT"
# validate: treat field as HHMMSScc, check HH<24 and MM<60 across sample
$ok=0;$bad=0
Get-Content $f -TotalCount 20000 | ForEach-Object {
  if($_.Length -ge 96){ $t=$_.Substring(88,8); $hh=[int]$t.Substring(0,2); $mm=[int]$t.Substring(2,2); $ss=[int]$t.Substring(4,2); if($hh -lt 24 -and $mm -lt 60 -and $ss -lt 60){$ok++}else{$bad++} }
}
"HHMMSScc valido: ok=$ok bad=$bad"

$p = "c:\Users\junioeg\robotics\robotics1\a"
"===== Busca '61610022782' (sem hifen) ====="
Get-ChildItem $p -File | ForEach-Object { $c=(Select-String -Path $_.FullName -SimpleMatch "61610022782" -AllMatches|Measure-Object).Count; if($c){ "{0,-25} {1}" -f $_.Name,$c } }
"===== Busca '6161-0022782' (com hifen) ====="
Get-ChildItem $p -File | ForEach-Object { $c=(Select-String -Path $_.FullName -SimpleMatch "6161-0022782" -AllMatches|Measure-Object).Count; if($c){ "{0,-25} {1}" -f $_.Name,$c } }
"===== Busca '0022782' ====="
Get-ChildItem $p -File | ForEach-Object { $c=(Select-String -Path $_.FullName -SimpleMatch "0022782" -AllMatches|Measure-Object).Count; if($c){ "{0,-25} {1}" -f $_.Name,$c } }

$p = "c:\Users\junioeg\robotics\robotics1\a"
foreach($fn in 'ALLTHK55.TXT','STKMTS.TXT','VRLOTES.TXT','N15THK55.TXT','N16THK55.TXT'){
  "===== $fn ====="
  Select-String -Path (Join-Path $p $fn) -SimpleMatch "0022782" | Select-Object -First 4 | ForEach-Object { "  L$($_.LineNumber): $($_.Line)" }
}
